import type GraphObjectType from "./GraphObjectType.js";
import type { GraphObjectTypeProperties } from "./GraphObjectType.js";

export interface RelationshipTypeProperties extends GraphObjectTypeProperties, Partial<Pick<RelationshipType, "endPoints">> {}

/**
 * A relationship type defines a homogenous collection of [relationships](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/Relationship/) that can exist between two [entity types](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/EntityType/),
 * with a common set of properties. For example, a relationship type defining vehicle
 * ownership can associate a vehicle with a person, and the relationship can have properties such as the date a person
 * bought the car and the date a person sold the car.
 *
 * Many instances of a relationship type can be added to the knowledge graph. For example, to describe a family, multiple instances of the spouse-of,
 * parent-of, and child-of relationships can be defined between two-person entities. Multiple instances of owns, leases,
 * or rents relationship types can be defined between a person entity and vehicle or building entities.
 *
 * @since 4.25
 * @see [EntityType](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/EntityType/)
 * @see [Relationship](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/Relationship/)
 */
export default class RelationshipType extends GraphObjectType {
  constructor(properties?: RelationshipTypeProperties);
  /**
   * Specifies valid origin and destination [entity type](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/EntityType/) pairs for this relationship.
   *
   * @example
   * //endpoints for the employed_by relationship
   * "endpoints": [
   *  {
   *   "originEntityType": "Person",
   *   "destinationEntityType": "Company"
   *  }
   * ]
   */
  accessor endPoints: RelationshipTypeEndPoints[];
}

export interface RelationshipTypeEndPoints {
  /** The `name` of the origin [entity type](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/EntityType/). */
  originEntityType: string;
  /** The `name` of the destination [entity type](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/EntityType/). */
  destinationEntityType: string;
}